54: // ── Helpers ──────────────────────────────────────────────────────────
55: 
56: fn toLower(c: u8) u8 {
57:     if (c >= 'A' and c <= 'Z') return c | 0x20;
58:     return c;
59: }
60: 
61: fn isVowel(c: u8) bool {
62:     return switch (toLower(c)) {
63:         'a', 'e', 'i', 'o', 'u', 'y' => true,
64:         else => false,
65:     };
66: }
67: 
68: fn isAlpha(c: u8) bool {
69:     return (c >= 'A' and c <= 'Z') or (c >= 'a' and c <= 'z');
70: }
71: 
72: fn toneIndex(t: u8) u8 {
73:     return switch (t) {
74:         0 => 0,
75:         's' => 1,
76:         'f' => 2,
77:         'r' => 3,
78:         'x' => 4,
79:         'j' => 5,
80:         else => 0,
81:     };
82: }
83: 
84: fn spanIsVowel(sp: Span) bool {
85:     return isVowel(sp.base);
86: }
87: 
88: fn spanIsOnsetBound(s: *State, idx: usize) bool {
89:     // Check if this vowel is onset-bound (i in gi, u in qu followed by another vowel)
90:     if (idx == 0) return false;
91:     const lo = toLower(s.spans[idx].base);
92:     const prev_lo = toLower(s.spans[idx - 1].base);
93: 
94:     // Must be a vowel to be onset-bound
95:     if (!isVowel(lo)) return false;
96: 
97:     // Check if there's a vowel after this one in the word
98:     var has_vowel_after = false;
99:     var k = idx + 1;
100:     while (k < s.len) : (k += 1) {
101:         if (spanIsVowel(s.spans[k])) {
102:             has_vowel_after = true;
103:             break;
104:         }
105:     }
106:     if (!has_vowel_after) return false;
107: 
108:     // gi: i after g is onset-bound
109:     if (lo == 'i' and prev_lo == 'g' and idx == 1) return true;
110:     // qu: u after q is onset-bound
111:     if (lo == 'u' and prev_lo == 'q' and idx == 1) return true;
112: 
113:     return false;
114: }
115: 
116: fn hasModifiedVowel(sp: Span) bool {
117:     return spanIsVowel(sp) and sp.modifier != 0;
118: }
119: 
120: // Region computation
121: const Regions = struct {
122:     nucleus_start: u8, // index of first nucleus vowel
123:     nucleus_end: u8, // index of last nucleus vowel (inclusive)
124:     coda_start: u8, // index of first coda consonant (== len if no coda)
125:     has_nucleus: bool,
126: };
127: 
128: fn computeRegions(s: *State) Regions {
129:     var r = Regions{
130:         .nucleus_start = s.len,
131:         .nucleus_end = 0,
132:         .coda_start = s.len,
133:         .has_nucleus = false,
134:     };
135: 
136:     // Find nucleus vowels (vowels that are not onset-bound)
137:     var i: u8 = 0;
138:     while (i < s.len) : (i += 1) {
139:         if (spanIsVowel(s.spans[i]) and !spanIsOnsetBound(s, i)) {
140:             if (!r.has_nucleus) {
141:                 r.nucleus_start = i;
142:                 r.has_nucleus = true;
143:             }
144:             r.nucleus_end = i;
145:         }
146:     }
147: 
148:     // Coda: consonants after last nucleus vowel
149:     if (r.has_nucleus) {
150:         r.coda_start = r.nucleus_end + 1;
151:         // Verify coda has consonants
152:         var found_coda = false;
153:         var k = r.coda_start;
154:         while (k < s.len) : (k += 1) {
155:             if (!spanIsVowel(s.spans[k])) {
156:                 found_coda = true;
157:                 break;
158:             }
159:         }
160:         if (!found_coda) {
161:             // Check for semi-vowel coda: trailing i/y/u/o in a multi-vowel nucleus
162:             const nv = nucleusVowelCount(s, r);
163:             if (nv >= 2) {
164:                 const last_lo = toLower(s.spans[r.nucleus_end].base);
165:                 if (last_lo == 'i' or last_lo == 'y' or last_lo == 'u' or last_lo == 'o') {
166:                     r.coda_start = r.nucleus_end;
167:                     r.nucleus_end -= 1;
168:                 }
169:             }
170:             if (r.coda_start >= s.len) {
171:                 r.coda_start = s.len;
172:             }
173:         }
174:     }
175: 
176:     return r;
177: }
178: 
179: fn nucleusVowelCount(s: *State, r: Regions) u8 {
180:     if (!r.has_nucleus) return 0;
181:     var count: u8 = 0;
182:     var i = r.nucleus_start;
183:     while (i <= r.nucleus_end) : (i += 1) {
184:         if (spanIsVowel(s.spans[i])) count += 1;
185:     }
186:     return count;
187: }
188: 
189: // Find the span index where a tone mark should be placed
190: fn findToneTarget(s: *State) ?u8 {
191:     const r = computeRegions(s);
192:     if (!r.has_nucleus) return null;
193: 
194:     // Rule 1: If a modified vowel exists, tone goes on the last one
195:     {
196:         var last_modified: ?u8 = null;
197:         var i = r.nucleus_start;
198:         while (i <= r.nucleus_end) : (i += 1) {
199:             if (hasModifiedVowel(s.spans[i])) {
200:                 last_modified = i;
201:             }
202:         }
203:         if (last_modified) |idx| return idx;
204:     }
205: 
206:     const nv = nucleusVowelCount(s, r);
207:     const has_coda = r.coda_start < s.len;
208: 
209:     // Rule 4: Single vowel → tone on that vowel
210:     if (nv == 1) return r.nucleus_start;
211: 
212:     // Rule 2: No modified vowel, no coda → tone on 1st nucleus vowel
213:     if (!has_coda) return r.nucleus_start;
214: 
215:     // Rule 3: No modified vowel, has coda → tone on 2nd nucleus vowel (if exists)
216:     if (nv >= 2) {
217:         var count: u8 = 0;
218:         var i = r.nucleus_start;
219:         while (i <= r.nucleus_end) : (i += 1) {
220:             if (spanIsVowel(s.spans[i])) {
221:                 count += 1;
222:                 if (count == 2) return i;
223:             }
224:         }
225:     }
226: 
227:     return r.nucleus_start;
228: }
