230: // Apply tone to correct vowel, clearing any existing tone on other vowels
231: fn applyTone(s: *State, tone: u8) void {
232:     const target = findToneTarget(s) orelse return;
233: 
234:     // Clear tone from all nucleus vowels
235:     var i: u8 = 0;
236:     while (i < s.len) : (i += 1) {
237:         if (spanIsVowel(s.spans[i])) {
238:             s.spans[i].tone = 0;
239:         }
240:     }
241: 
242:     // Set tone on target
243:     s.spans[target].tone = tone;
244: }
