375: export fn backspace(state: *anyopaque) u8 {
376:     const s: *State = @ptrCast(@alignCast(state));
377:     if (s.len == 0) return 0;
378:     s.len -= 1;
379:     // Clear the removed span
380:     s.spans[s.len] = std.mem.zeroes(Span);
381:     // If all spans removed, reset mode
382:     if (s.len == 0) s.mode = 0;
383:     return 1;
