882:     // Append literal character when possible. Then inclease the buffer_length.
883:     fn append_literal(self: *State, c: u8) void {
884:         // Only allow a-zA-Z.
885:         assert(std.ascii.isAlphabetic(c));
886:         // Could not append if the buffer_length is full.
887:         assert(self.buffer_length < std.math.maxInt(@TypeOf(self.buffer_length)));
888: 
889:         // Check if we can add new span for input character.
890:         if (self.buffer_length < self.buffer_effective.len) {
891:             // Add character to span.
892:             self.buffer_effective[self.buffer_length] = Span.init(c);
893:         }
894:         // Increase the buffer length for tracking, we will need it went handling backspace.
895:         self.buffer_length += 1;
896: 
897:         // After increase, the new buffer_length may exceed the buffer_effective, set literal_index if needed.
898:         if (self.mode == .telex and self.literal_index == null and self.buffer_length == self.buffer_effective.len + 1) {
899:             self.literal_index = self.buffer_length - 1;
900:         }
901:     }
