904:     fn buffer_effective_last(self: *State) Span {
905:         // 1. Should not work if buffer_length exceed buffer_effective.
906:         // 2. Bufeer must have al least 1 character.
907:         assert(self.buffer_length > 0 and self.buffer_length <= self.buffer_effective.len);
908: 
909:         return self.buffer_effective[self.buffer_length - 1];
